idth:34px}#ub-gdpr input[type=checkbox]:checked:before{color:#fff;content:"on";left:1px;right:auto}#ub-gdpr input[type=checkbox]:disabled:before{color:#c9c9c9}#ub-gdpr-banner{border-width:2px 0 0;bottom:0;flex-wrap:wrap;gap:25px;justify-content:space-between;z-index:99999998}#ub-gdpr-banner-text{flex:1 250px;max-width:600px}#ub-gdpr-banner-buttons{display:flex;flex-wrap:wrap;gap:15px}#ub-gdpr-modal{background-color:hsla(0,0%,100%,.6);bottom:0;flex-direction:column;justify-content:center;top:0;z-index:99999999}#ub-gdpr-modal .ub-gdpr-heading{align-items:center;border-bottom:1px solid #d8d8d8;display:flex;font-size:20px;justify-content:space-between;margin-bottom:0;padding:24px}#ub-gdpr-modal .ub-gdpr-heading button{background:none;border:none;flex-grow:0;font-size:30px;padding:0}#ub-gdpr-modal .ub-gdpr-heading button:focus,#ub-gdpr-modal .ub-gdpr-heading button:hover{color:#03f}#ub-gdpr-modal-content{display:flex;flex-direction:column;max-height:100%;max-width:600px}#ub-gdpr-modal-categories{-webkit-overflow-scrolling:touch;overflow:auto;overscroll-behavior:contain}#ub-gdpr-modal-categories .ub-gdpr-modal-category{border-bottom:1px solid #d8d8d8;display:flex;gap:10px;justify-content:space-between;margin:0 24px;padding:24px 0}#ub-gdpr-modal-buttons{padding:24px}
